def compute_qwen3moe_layer_lora_numel(config, lora_ranks: dict, layer_idx: int = 0, verbose: bool = False):
    """
    Compute per-layer LoRA parameter count for the Qwen3Moe family.

    All layers have attention LoRA (4 projections: q, k, v, o); dense-MLP layers
    also have MLP LoRA (3 projections: gate, up, down); MoE layers have expert LoRA
    (num_experts * 3 projections: gate, up, down per expert).

    Args:
        config: Model config object (must have ``decoder_sparse_step``).
        lora_ranks: Dict mapping component name to its LoRA rank.
        layer_idx: Which layer to compute for.
        verbose: If True, return (total, detail_string) instead of just total.

    Returns:
        int if verbose=False, or (int, str) if verbose=True.
    """
    from src_transformers_lora.LoraHelper import _lora_linear_numel_detail

    hidden = config.hidden_size
    n_heads = config.num_attention_heads
    n_kv_heads = config.num_key_value_heads
    head_dim = getattr(config, "head_dim", hidden // n_heads)
    attn_bias = getattr(config, "attention_bias", False)

    q_dim = n_heads * head_dim
    total = 0
    details = []
    details.append(f"  Config: hidden={hidden}, n_heads={n_heads}, n_kv_heads={n_kv_heads}, "
                   f"head_dim={head_dim}, q_dim={q_dim}, attn_bias={attn_bias}, lora_ranks={lora_ranks}")

    n, d = _lora_linear_numel_detail("q_proj", hidden, q_dim, lora_ranks["q_proj"], attn_bias)
    total += n; details.append(d)
    n, d = _lora_linear_numel_detail("k_proj", hidden, n_kv_heads * head_dim, lora_ranks["k_proj"], attn_bias)
    total += n; details.append(d)
    n, d = _lora_linear_numel_detail("v_proj", hidden, n_kv_heads * head_dim, lora_ranks["v_proj"], attn_bias)
    total += n; details.append(d)
    n, d = _lora_linear_numel_detail("o_proj", q_dim, hidden, lora_ranks["o_proj"], attn_bias)
    total += n; details.append(d)

    # Determine if this is a MoE layer or dense MLP layer
    mlp_only_layers = getattr(config, "mlp_only_layers", []) or []
    num_experts = getattr(config, "num_experts", 0)
    decoder_sparse_step = config.decoder_sparse_step
    is_moe_layer = (
        layer_idx not in mlp_only_layers
        and num_experts > 0
        and (layer_idx + 1) % decoder_sparse_step == 0
    )
    if not is_moe_layer:
        # Dense MLP LoRA
        intermediate = config.intermediate_size
        n, d = _lora_linear_numel_detail("mlp_gate", hidden, intermediate, lora_ranks["mlp_gate"], False)
        total += n; details.append(d)
        n, d = _lora_linear_numel_detail("mlp_up", hidden, intermediate, lora_ranks["mlp_up"], False)
        total += n; details.append(d)
        n, d = _lora_linear_numel_detail("mlp_down", intermediate, hidden, lora_ranks["mlp_down"], False)
        total += n; details.append(d)
    else:
        # Expert LoRA
        moe_intermediate = config.moe_intermediate_size
        details.append(f"  Expert LoRA ({num_experts} experts):")
        n_gate, d = _lora_linear_numel_detail("expert_gate", hidden, moe_intermediate, lora_ranks["expert_gate"], False)
        details.append(f"    per-expert: {d}")
        n_up, d = _lora_linear_numel_detail("expert_up", hidden, moe_intermediate, lora_ranks["expert_up"], False)
        details.append(f"    per-expert: {d}")
        n_down, d = _lora_linear_numel_detail("expert_down", moe_intermediate, hidden, lora_ranks["expert_down"], False)
        details.append(f"    per-expert: {d}")
        expert_total = (n_gate + n_up + n_down) * num_experts
        total += expert_total
        details.append(f"    expert_total = ({n_gate} + {n_up} + {n_down}) * {num_experts} = {expert_total}")

    details.append(f"  TOTAL = {total}")
    if verbose:
        return total, "\n".join(details)
    return total
